// Check if conversation already has a client label.
// If yes → skip AI. If no → extract email content for classification.
//
// Handles both Missive webhook shapes:
//   Rule trigger:    body.latest_message
//   Comment trigger:  body.message

const webhook = $('3CV Email Webhook').first().json;
const body = webhook.body || webhook;
const conversation = body.conversation || {};

// Extract message from either webhook shape
const message = body.latest_message || body.message || (body.messages || [])[0] || {};

// Current conversation labels
const convLabelIds = new Set(
  (conversation.shared_labels || []).map(l => l.id)
);

// Filter DataTable to recipient leaf labels (client-eligible)
const allLabels = $('Get Missive Labels').all();
const clientLabels = allLabels.filter(l => {
  const j = l.json;
  return j.category === 'Recipients'
    && j.is_leaf === 'true'
    && ['Current Clients', 'Prospects', 'Former clients'].includes(j.sub_category);
});

// Check if any existing label is already a client label
const existingClientLabels = clientLabels
  .filter(cl => convLabelIds.has(cl.json.label_id))
  .map(cl => cl.json.label_name);

if (existingClientLabels.length > 0) {
  return [{ alreadyClassified: true }];
}

// Extract email content from whichever message shape we got
const subject = conversation.subject || message.subject || '';
const emailBody = (message.body || message.preview || '')
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .substring(0, 3000);

return [{
  alreadyClassified: false,
  conversationId: conversation.id,
  subject: subject,
  emailBody: emailBody
}];

