// Parse Classification Agent structured output                       
// Output parser returns: { clients: [...], label_ids: [...] }

const agentOutput = $('Classification Agent').first().json;
const conversationId = $('Check Existing Labels').first().json.conversationId;

// With structured output parser, output is already an object
const output = agentOutput.output || {};
const labelIds = output.label_ids || [];

if (labelIds.length === 0) {
  return [{ conversationId, labelIds: [], skip: true }];
}

return [{ conversationId, labelIds, skip: false }];

